import { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const OAuthCallbackPage = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const handleCallback = async () => {
      try {
        const params = new URLSearchParams(window.location.search);
        const response = await axios.get(`http://localhost:5000/api/auth/google/callback?${params.toString()}`);

        if (response.data.success) {
          console.log('Logged in user:', response.data.data.user);
          localStorage.setItem('user', JSON.stringify(response.data.data.user));
          navigate('/dashboard'); // Change this to your intended route
        } else {
          console.error('OAuth failed:', response.data.error);
        }
      } catch (error) {
        console.error('OAuth callback error:', error);
      }
    };

    handleCallback();
  }, [navigate]);

  return <p>Logging you in, please wait...</p>;
};

export default OAuthCallbackPage;
